-- ==========================================================
-- accounts seed — реф accounting.db-гээс шилжүүлсэн дансны мод
-- Нийт: 367 мөр. parent_id холбоос хадгалагдсан тул id-г шууд оруулна.
-- Хүснэгт хоосон үед л оруулна (дахин ажиллуулахад давхардахгүй).
-- Supabase SQL Editor-д ажиллуулна.
-- ==========================================================

DO $$
BEGIN
IF (SELECT COUNT(*) FROM accounts) = 0 THEN


-- BIGSERIAL дарааллыг хамгийн их id-ийн дараа тавина
PERFORM setval(pg_get_serial_sequence('accounts','id'),
               (SELECT MAX(id) FROM accounts));

END IF;
END $$;
